@import"https://fonts.googleapis.com/css2?family=Noto+Sans+SC:wght@400;500;700&display=swap";*{box-sizing:border-box;margin:0;padding:0}.app-root{width:100%;height:600px;background:var(--uc-bg, #0f0c1a);font-family:var(--uc-font-family, "Noto Sans SC", "PingFang SC", "Microsoft YaHei", sans-serif);border-radius:20px;overflow:hidden;color:var(--uc-text, #e8e0f0);display:flex;flex-direction:column;position:relative}.status-bar{display:flex;align-items:center;justify-content:space-between;padding:10px 14px 8px;background:color-mix(in srgb, var(--uc-panel-bg, #1a1028) 82%, transparent);border-bottom:1px solid var(--uc-border, rgba(255, 255, 255, 0.06));gap:6px}.status-left,.status-right{display:flex;gap:5px;align-items:center}.status-center{flex:1;display:flex;justify-content:center}.date-chip,.week-chip,.weather-chip{font-size:10px;padding:2px 7px;border-radius:20px;background:color-mix(in srgb, var(--uc-panel-bg, #1a1028) 72%, white 12%);color:var(--uc-muted, #b8a8d0);letter-spacing:.3px}.time-badge{font-size:11px;font-weight:600;padding:3px 10px;border-radius:20px;background:color-mix(in srgb, var(--uc-accent, #a78bfa) 22%, transparent);border:1px solid color-mix(in srgb, var(--uc-accent, #a78bfa) 45%, transparent);color:var(--uc-accent, #d8b4fe);letter-spacing:.5px}.history-btn{width:24px;height:24px;border-radius:50%;border:none;background:color-mix(in srgb, var(--uc-panel-bg, #1a1028) 70%, white 10%);color:var(--uc-muted, #6b5f80);font-size:11px;cursor:pointer;display:flex;align-items:center;justify-content:center;transition:all .15s}.history-btn.active,.history-btn:hover{background:color-mix(in srgb, var(--uc-accent, #a78bfa) 22%, transparent);color:var(--uc-accent, #a78bfa)}.thinking-bar{display:flex;align-items:center;gap:8px;padding:8px 14px;font-size:12px;color:var(--uc-muted, #7c6f96);background:color-mix(in srgb, var(--uc-accent, #a78bfa) 8%, transparent);border-bottom:1px solid color-mix(in srgb, var(--uc-accent, #a78bfa) 16%, transparent)}.thinking-spin{color:var(--uc-accent, #a78bfa);font-size:13px}.tab-bar{display:flex;padding:0 8px;gap:4px;margin-top:8px;background:color-mix(in srgb, var(--uc-panel-bg, #1a1028) 86%, black 12%);border-bottom:1px solid var(--uc-border, rgba(255, 255, 255, 0.05))}.tab-btn{flex:1;display:flex;align-items:center;justify-content:center;gap:5px;padding:9px 4px;border:none;background:rgba(0,0,0,0);color:var(--uc-muted, #6b5f80);font-size:12px;font-weight:500;cursor:pointer;transition:all .2s;border-bottom:2px solid rgba(0,0,0,0)}.tab-btn i{font-size:11px}.tab-btn.active{color:var(--uc-accent, #c084fc);border-bottom-color:var(--uc-accent, #c084fc);background:color-mix(in srgb, var(--uc-accent, #c084fc) 10%, transparent)}.tab-content{flex:1;overflow-y:auto;min-height:0;padding:12px}.input-bar{display:flex;gap:8px;padding:10px 12px 12px;border-top:1px solid var(--uc-border, rgba(255, 255, 255, 0.07));background:color-mix(in srgb, var(--uc-panel-bg, #1a1028) 88%, black 12%)}.input-field{flex:1;background:var(--uc-input-bg, rgba(255, 255, 255, 0.07));border:1px solid var(--uc-border, rgba(255, 255, 255, 0.1));border-radius:20px;padding:9px 14px;color:var(--uc-text, #e8e0f0);font-size:13px;outline:none;font-family:inherit}.input-field::placeholder{color:var(--uc-muted, #4a4060)}.input-field:focus{border-color:var(--uc-accent, #a78bfa)}.input-field:disabled{opacity:.5}.send-btn{width:38px;height:38px;border-radius:50%;border:none;flex-shrink:0;background:linear-gradient(135deg, color-mix(in srgb, var(--uc-accent, #a78bfa) 72%, #000), var(--uc-accent, #a78bfa));color:#fff;font-size:13px;cursor:pointer;display:flex;align-items:center;justify-content:center;transition:opacity .15s}.send-btn:disabled{opacity:.4;cursor:not-allowed}.regen-btn{width:38px;height:38px;border-radius:50%;border:1px solid color-mix(in srgb, var(--uc-accent, #a78bfa) 35%, transparent);flex-shrink:0;background:color-mix(in srgb, var(--uc-accent, #a78bfa) 14%, var(--uc-panel-bg, #1a1028));color:var(--uc-accent, #d8b4fe);font-size:13px;cursor:pointer;display:flex;align-items:center;justify-content:center;transition:opacity .15s,transform .15s,background .15s}.regen-btn:hover:not(:disabled){background:color-mix(in srgb, var(--uc-accent, #a78bfa) 24%, var(--uc-panel-bg, #1a1028));transform:translateY(-1px)}.regen-btn:disabled{opacity:.4;cursor:not-allowed}.history-panel{position:absolute;inset:0;z-index:200;background:rgba(0,0,0,.6);backdrop-filter:blur(4px);display:flex;flex-direction:column}.history-inner{margin:auto 0 0;max-height:75%;background:var(--uc-panel-bg, #1a1028);border-top:1px solid var(--uc-border, rgba(255, 255, 255, 0.1));border-radius:20px 20px 0 0;display:flex;flex-direction:column;overflow:hidden}.history-header{display:flex;align-items:center;justify-content:space-between;padding:12px 16px;font-size:13px;font-weight:700;color:var(--uc-accent, #c084fc);border-bottom:1px solid var(--uc-border, rgba(255, 255, 255, 0.07));flex-shrink:0}.h-count{font-size:10px;color:var(--uc-muted, #6b5f80);font-weight:400;margin-left:4px}.h-close{background:none;border:none;color:var(--uc-muted, #6b5f80);font-size:14px;cursor:pointer}.h-loading,.h-empty{padding:24px;text-align:center;font-size:12px;color:var(--uc-muted, #4a3f60)}.h-list{overflow-y:auto;padding:8px;display:flex;flex-direction:column;gap:6px}.h-item{border-radius:10px;padding:10px 12px}.h-item.user{background:rgba(99,102,241,.08);border-left:2px solid rgba(99,102,241,.4)}.h-item.assistant{background:color-mix(in srgb, var(--uc-accent, #a78bfa) 10%, transparent);border-left:2px solid color-mix(in srgb, var(--uc-accent, #a78bfa) 55%, transparent)}.h-item.hidden{opacity:.6}.h-item-head{display:flex;align-items:center;gap:6px;margin-bottom:5px}.h-role{font-size:10px;font-weight:700;color:#7c6f96}.h-id{font-size:10px;color:var(--uc-muted, #4a3f60);flex:1}.h-hidden-tag{font-size:9px;padding:1px 5px;border-radius:6px;background:rgba(251,191,36,.15);color:#fbbf24;border:1px solid rgba(251,191,36,.3)}.h-expand{background:none;border:none;color:#4a3f60;font-size:10px;cursor:pointer;padding:2px 4px}.h-expand:hover{color:var(--uc-accent, #a78bfa)}.h-rollback{font-size:10px;padding:2px 8px;border-radius:10px;border:none;background:rgba(239,68,68,.15);color:#f87171;cursor:pointer;display:flex;align-items:center;gap:4px}.h-rollback:hover{background:rgba(239,68,68,.25)}.h-content{font-size:12px;color:var(--uc-text, #9d8fb0);line-height:1.6;white-space:pre-wrap;max-height:72px;overflow:hidden;display:-webkit-box;-webkit-line-clamp:4;-webkit-box-orient:vertical}.h-content.expanded{max-height:none;display:block;-webkit-line-clamp:unset}.debug-panel{position:absolute;inset:0;z-index:300;background:#0a0a0f;display:flex;flex-direction:column}.debug-header{display:flex;align-items:center;justify-content:space-between;padding:8px 12px;font-size:12px;font-weight:700;color:#34d399;border-bottom:1px solid rgba(52,211,153,.2);flex-shrink:0}.debug-pre{flex:1;overflow-y:auto;padding:10px 12px;font-size:11px;line-height:1.6;color:#9d8fb0;white-space:pre-wrap;word-break:break-all;font-family:"Courier New",monospace}.settings-panel{position:absolute;inset:0;z-index:260;background:rgba(0,0,0,.62);backdrop-filter:blur(4px);display:flex;flex-direction:column}.settings-inner{margin:auto 0 0;max-height:82%;background:var(--uc-panel-bg, #1a1028);border-top:1px solid var(--uc-border, rgba(255, 255, 255, 0.1));border-radius:20px 20px 0 0;overflow:hidden;display:flex;flex-direction:column}.settings-header{display:flex;align-items:center;justify-content:space-between;padding:12px 16px;color:var(--uc-accent, #c084fc);font-size:13px;font-weight:700;border-bottom:1px solid var(--uc-border, rgba(255, 255, 255, 0.07))}.settings-actions{display:flex;align-items:center;gap:8px}.settings-small-btn{border:1px solid var(--uc-border, rgba(255, 255, 255, 0.1));background:color-mix(in srgb, var(--uc-accent, #a78bfa) 12%, transparent);color:var(--uc-accent, #a78bfa);border-radius:8px;padding:4px 8px;font-size:11px;cursor:pointer}.settings-body{padding:12px;overflow-y:auto;display:flex;flex-direction:column;gap:10px}.settings-row{display:flex;flex-direction:column;gap:5px;font-size:11px;color:var(--uc-muted, #7c6f96)}.settings-row input{width:100%;border:1px solid var(--uc-border, rgba(255, 255, 255, 0.1));border-radius:8px;background:var(--uc-input-bg, #251d32);color:var(--uc-text, #e8e0f0);padding:7px 9px;font-size:12px;outline:none;font-family:inherit}.settings-row input:focus{border-color:var(--uc-accent, #a78bfa)}.settings-grid{display:grid;grid-template-columns:repeat(2, minmax(0, 1fr));gap:8px}.color-row{display:flex;align-items:center;justify-content:space-between;gap:8px;min-width:0;border:1px solid var(--uc-border, rgba(255, 255, 255, 0.08));border-radius:8px;padding:8px;color:var(--uc-muted, #7c6f96);font-size:11px}.color-row span{min-width:0;overflow:hidden;text-overflow:ellipsis;white-space:nowrap}.color-row input{width:34px;height:24px;border:none;background:rgba(0,0,0,0);cursor:pointer;flex-shrink:0}