
.story-tab {
  display: flex;
  flex-direction: column;
  gap: 10px;
}

.narrative-box {
  padding: 14px;
  background: var(--uc-story-bg, rgba(255, 255, 255, 0.03));
  border-left: 3px solid var(--uc-accent, #a78bfa);
  border-radius: 0 10px 10px 0;
  min-height: 60px;
}
.thinking-bar {
  display: flex;
  align-items: center;
  gap: 8px;
  font-size: 12px;
  color: var(--uc-muted, #7c6f96);
  margin-bottom: 8px;
  i {
    color: var(--uc-accent, #a78bfa);
  }
}
.narrative-text {
  font-size: 13px;
  line-height: 1.9;
  color: var(--uc-text, #d4cce8);
  word-break: break-word;
  :deep(p) {
    margin: 0 0 0.75em;
    white-space: pre-wrap;
  }
  :deep(p:last-child) {
    margin-bottom: 0;
  }
  :deep(strong) {
    color: var(--uc-md-bold, #f9a8d4);
    font-weight: 700;
  }
  :deep(em) {
    color: var(--uc-md-italic, #93c5fd);
    font-style: italic;
  }
  :deep(code) {
    color: var(--uc-md-code, #86efac);
    background: var(--uc-md-code-bg, #10151d);
    border: 1px solid var(--uc-border, rgba(255, 255, 255, 0.08));
    border-radius: 4px;
    padding: 1px 4px;
    font-family: 'Courier New', monospace;
    font-size: 0.94em;
  }
  :deep(pre) {
    margin: 8px 0;
    padding: 10px 12px;
    overflow-x: auto;
    border-radius: 8px;
    background: var(--uc-md-code-bg, #10151d);
    border: 1px solid var(--uc-border, rgba(255, 255, 255, 0.08));
  }
  :deep(pre code) {
    padding: 0;
    border: none;
    background: transparent;
    white-space: pre;
    display: block;
  }
  :deep(blockquote) {
    margin: 6px 0;
    padding: 4px 0 4px 10px;
    border-left: 2px solid var(--uc-accent, #a78bfa);
    color: color-mix(in srgb, var(--uc-text, #d4cce8) 78%, white 10%);
  }
  :deep(ul) {
    margin: 6px 0 8px 18px;
  }
  :deep(h3),
  :deep(h4),
  :deep(h5) {
    margin: 10px 0 6px;
    color: var(--uc-accent, #a78bfa);
    font-size: 1.05em;
  }
  :deep(.quote-double) {
    color: var(--uc-quote-double, #fbbf24);
  }
  :deep(.quote-single) {
    color: var(--uc-quote-single, #5eead4);
  }
  :deep(.quote-bracket) {
    color: var(--uc-quote-bracket, #c4b5fd);
  }
  :deep(.quote-chinese) {
    color: var(--uc-quote-chinese, #fb7185);
  }
}
.narrative-empty {
  font-size: 12px;
  color: var(--uc-muted, #4a3f60);
}
.cursor-blink {
  display: inline-block;
  width: 2px;
  height: 13px;
  background: var(--uc-accent, #a78bfa);
  margin-left: 2px;
  vertical-align: middle;
  animation: blink 1s step-end infinite;
}
@keyframes blink {
  0%,
  100% {
    opacity: 1;
  }
  50% {
    opacity: 0;
  }
}

.npc-scene {
  border-radius: 10px;
  background: var(--uc-story-bg, rgba(255, 255, 255, 0.03));
  border: 1px solid var(--uc-border, rgba(255, 255, 255, 0.07));
  overflow: hidden;
}
.update-card {
  border-radius: 14px;
  background:
    linear-gradient(180deg, color-mix(in srgb, var(--uc-accent, #a78bfa) 12%, transparent), transparent 60%),
    color-mix(in srgb, var(--uc-panel-bg, #1a1028) 92%, black 8%);
  border: 1px solid color-mix(in srgb, var(--uc-accent, #a78bfa) 22%, var(--uc-border, rgba(255, 255, 255, 0.08)));
  overflow: hidden;
  box-shadow: 0 10px 24px rgba(0, 0, 0, 0.18);
}
.update-summary {
  list-style: none;
  display: flex;
  align-items: center;
  justify-content: space-between;
  gap: 10px;
  padding: 12px 14px;
  cursor: pointer;
  color: var(--uc-text, #d4cce8);
  &::-webkit-details-marker {
    display: none;
  }
}
.update-summary-main {
  display: flex;
  align-items: center;
  gap: 10px;
  min-width: 0;
}
.update-badge {
  padding: 4px 8px;
  border-radius: 999px;
  font-size: 10px;
  font-weight: 700;
  letter-spacing: 0.4px;
  text-transform: uppercase;
  color: #f8f5ff;
  background: linear-gradient(
    135deg,
    color-mix(in srgb, var(--uc-accent, #a78bfa) 80%, white 8%),
    color-mix(in srgb, var(--uc-accent, #a78bfa) 55%, black 10%)
  );
}
.update-title {
  font-size: 13px;
  font-weight: 700;
  color: var(--uc-text, #efe8ff);
}
.update-hint {
  font-size: 11px;
  color: var(--uc-muted, #8d80aa);
  white-space: nowrap;
}
.update-body {
  padding: 0 14px 14px;
  display: flex;
  flex-direction: column;
  gap: 12px;
}
.update-section {
  border-radius: 12px;
  background: color-mix(in srgb, var(--uc-story-bg, #171222) 80%, black 10%);
  border: 1px solid var(--uc-border, rgba(255, 255, 255, 0.08));
  overflow: hidden;
}
.update-section-title {
  padding: 10px 12px;
  font-size: 11px;
  font-weight: 700;
  letter-spacing: 0.4px;
  text-transform: uppercase;
  color: var(--uc-accent, #c4b5fd);
  background: color-mix(in srgb, var(--uc-accent, #a78bfa) 10%, transparent);
  border-bottom: 1px solid var(--uc-border, rgba(255, 255, 255, 0.06));
}
.update-analysis {
  padding: 12px;
  font-size: 12px;
  line-height: 1.8;
  color: var(--uc-text, #ddd6f3);
  :deep(p) {
    margin: 0 0 0.75em;
    white-space: pre-wrap;
  }
  :deep(p:last-child) {
    margin-bottom: 0;
  }
  :deep(ul) {
    margin: 6px 0 0 18px;
  }
  :deep(h3),
  :deep(h4),
  :deep(h5) {
    margin: 0 0 8px;
    color: var(--uc-accent, #a78bfa);
    font-size: 1em;
  }
  :deep(strong) {
    color: var(--uc-md-bold, #f9a8d4);
  }
  :deep(em) {
    color: var(--uc-md-italic, #93c5fd);
  }
  :deep(code) {
    color: var(--uc-md-code, #86efac);
    background: var(--uc-md-code-bg, #10151d);
    border-radius: 4px;
    padding: 1px 4px;
  }
}
.update-code {
  margin: 0;
  padding: 12px;
  overflow-x: auto;
  font-size: 12px;
  line-height: 1.7;
  color: #d6ffe8;
  background: linear-gradient(180deg, rgba(16, 21, 29, 0.96), rgba(12, 16, 24, 0.98));
  font-family: 'Courier New', monospace;
}
.scene-summary {
  padding: 10px 14px;
  font-size: 12px;
  font-weight: 600;
  color: var(--uc-muted, #7c6f96);
  cursor: pointer;
  list-style: none;
  display: flex;
  align-items: center;
  gap: 7px;
  &::-webkit-details-marker {
    display: none;
  }
  i {
    font-size: 11px;
    color: var(--uc-muted, #6b5f80);
  }
  &:hover {
    color: var(--uc-accent, #a78bfa);
  }
}
.scene-text {
  padding: 0 14px 12px;
  font-size: 12px;
  line-height: 1.8;
  color: var(--uc-text, #9d8fb0);
  white-space: pre-wrap;
}
